import Link from "next/link";

type CTAButtonProps = {
  href: string;
  children: React.ReactNode;
  variant?: "primary" | "secondary";
};

export default function CTAButton({
  href,
  children,
  variant = "primary"
}: CTAButtonProps) {
  const classes =
    variant === "primary"
      ? "bg-[#D83A8C] text-white shadow-[0_14px_30px_rgba(216,58,140,0.28)] hover:bg-[#C72F7E] hover:shadow-[0_18px_40px_rgba(216,58,140,0.35)]"
      : "border border-slate-200 bg-white text-slate-700 hover:border-[#D83A8C]/30 hover:bg-[#FFF1F8] hover:text-[#D83A8C]";

  return (
    <Link
      href={href}
      className={`inline-flex items-center justify-center rounded-2xl px-7 py-4 text-sm font-black transition-all duration-300 hover:-translate-y-0.5 ${classes}`}
    >
      {children}
    </Link>
  );
}